  assertEqual(result.rows[1]["notes"], 'Needs "improvement"', "Escaped quotes in notes");

  assertEqual(result.rows[2]["active"], true, "TRUE coerced to boolean");
  assertEqual(result.rows[2]["notes"], null, "Empty notes → null");

  assertEqual(result.rows[3]["name"], "Diana, Jr.", "Comma in quoted name");
  assertEqual(result.rows[3]["notes"], 'She said "hi"', "Escaped quotes at end");

  assertClose(result.sum("score"), 95.5 + 87 + 92.0, 0.001, "Sum of scores (nulls excluded)");
  assertClose(result.average("score"), (95.5 + 87 + 92.0) / 3, 0.001, "Average of scores");

  const highScorers = result.filter(function(r) { return typeof r["score"] === "number" && r["score"] > 90; });
  assertEqual(highScorers.length, 2, "Two high scorers (>90)");

  const byActive = result.groupBy("active");
  assertEqual(byActive.get(true).length, 2, "Two active");
  assertEqual(byActive.get(false).length, 2, "Two inactive");
}

// Summary
