// ─── Types ───────────────────────────────────────────────────────────────────

export interface CSVOptions {
  delimiter?: string;
  quote?: string;
  lineSeparator?: string;
  typeCoercion?: boolean;
}

export interface CSVError {
  row: number;
  message: string;
}

export interface CSVResult {
  rows: Record<string, unknown>[];
  headers: string[];
  errors: CSVError[];
  filter(predicate: (row: Record<string, unknown>) => boolean): Record<string, unknown>[];
  sum(column: string): number;
  average(column: string): number;
  count(): number;
  groupBy(column: string): Map<unknown, Record<string, unknown>[]>;
}

// ─── Field-level tokeniser (handles quoting / escaping) ─────────────────────

function parseRow(
  line: string,
  delimiter: string,
  quote: string
): { fields: string[]; error: string | null } {
  const fields: string[] = [];
  let i = 0;
  let error: string | null = null;

  while (i <= line.length) {
    // We're at the start of a new field
    if (i === line.length) {
      // Trailing delimiter produced an empty field
      // Only push if the last char was a delimiter (handled below after loop)
      break;
    }

    if (line[i] === quote) {
      // ── Quoted field ──────────────────────────────────────────────────
      i++; // skip opening quote
      let value = "";
      let closed = false;

      while (i < line.length) {
        if (line[i] === quote) {
          // Could be escaped quote ("") or closing quote
          if (i + 1 < line.length && line[i + 1] === quote) {
            value += quote;
            i += 2; // skip both quotes
          } else {
            // Closing quote
            i++; // skip closing quote
            closed = true;
            break;
          }
        } else {
          value += line[i];
          i++;
        }
      }

      if (!closed) {
        error = "Unterminated quoted field";
      }

      // After closing quote we expect either delimiter or end-of-line
      if (i < line.length && line[i] !== delimiter) {
        // There is trailing content after the closing quote — consume until
        // next delimiter and flag an error.
        let extra = "";
        while (i < line.length && line[i] !== delimiter) {
          extra += line[i];
          i++;
        }
        if (!error) {
          error = `Unexpected content after closing quote: "${extra}"`;
        }
      }

      // Skip delimiter
      if (i < line.length && line[i] === delimiter) {
        i++;
      }

      fields.push(value);
    } else {
      // ── Unquoted field ────────────────────────────────────────────────
      let value = "";
      while (i < line.length && line[i] !== delimiter) {
        value += line[i];
        i++;
      }
      // Skip delimiter
      if (i < line.length && line[i] === delimiter) {
        i++;
        // If we're now at end-of-line the trailing delimiter means an extra
        // empty field — we'll push it in the next iteration handled below.
        if (i === line.length) {
          fields.push(value);
          fields.push(""); // trailing empty field
          break;
        }
      }
      fields.push(value);
    }
  }

  return { fields, error };
}

// ─── Type coercion ──────────────────────────────────────────────────────────

function coerce(value: string): unknown {
  // Null / empty
  if (value === "" || value === "null" || value === "NULL") {
    return null;
  }

  // Boolean
  const lower = value.toLowerCase();
  if (lower === "true") return true;
  if (lower === "false") return false;

  // Number — must match the entire string (no leading/trailing whitespace noise
  // because we've already trimmed during field extraction)
  if (/^[+-]?(\d+\.?\d*|\.\d+)([eE][+-]?\d+)?$/.test(value)) {
    const num = Number(value);
    if (!Number.isNaN(num)) return num;
  }

  return value;
}

// ─── Line splitter (respects quoted fields spanning "lines") ────────────────

function splitLines(input: string, lineSeparator: string | undefined, quote: string): string[] {
  // If a custom line separator is given we do a simple split (users are in
  // control and quoted fields should not contain it).
  if (lineSeparator !== undefined) {
    return input.split(lineSeparator);
  }

  // Default behaviour: split on \r\n, \n, or \r BUT respect quoted regions.
  const lines: string[] = [];
  let current = "";
  let inQuotes = false;
  let i = 0;

  while (i < input.length) {
    const ch = input[i];

    if (ch === quote) {
      // Toggle quote state (escaped quotes "" will toggle twice → same state)
      inQuotes = !inQuotes;
      current += ch;
      i++;
    } else if (!inQuotes && (ch === "\r" || ch === "\n")) {
      lines.push(current);
      current = "";
      // Handle \r\n as single separator
      if (ch === "\r" && i + 1 < input.length && input[i + 1] === "\n") {
        i += 2;
      } else {
        i++;
      }
    } else {
      current += ch;
      i++;
    }
  }

  // Push last line (if any content)
  if (current.length > 0 || lines.length > 0) {
    lines.push(current);
  }

  return lines;
}

// ─── Main entry point ───────────────────────────────────────────────────────

export function parseCSV(input: string, options?: CSVOptions): CSVResult {
  const delimiter = options?.delimiter ?? ",";
  const quote = options?.quote ?? '"';
  const lineSeparator = options?.lineSeparator;
  const shouldCoerce = options?.typeCoercion !== false; // default true

  const rows: Record<string, unknown>[] = [];
  const errors: CSVError[] = [];

  // Handle empty / whitespace-only input
  if (input.trim().length === 0) {
    return buildResult([], [], []);
  }

  const lines = splitLines(input, lineSeparator, quote);

  // Strip trailing empty line produced by a final newline
  if (lines.length > 0 && lines[lines.length - 1] === "") {
    lines.pop();
  }

  if (lines.length === 0) {
    return buildResult([], [], []);
  }

  // ── Parse headers (first line) ────────────────────────────────────────────
  const headerResult = parseRow(lines[0], delimiter, quote);
  const headers = headerResult.fields.map((h) => h.trim());

  if (headerResult.error) {
    errors.push({ row: 1, message: `Header row: ${headerResult.error}` });
  }

  // ── Parse data rows ──────────────────────────────────────────────────────
  for (let idx = 1; idx < lines.length; idx++) {
    const line = lines[idx];

    // Skip completely empty lines
    if (line.trim() === "") continue;

    const rowNum = idx + 1; // 1-based row number (header = row 1)
    const { fields, error } = parseRow(line, delimiter, quote);

    if (error) {
      errors.push({ row: rowNum, message: error });
      // Still try to use whatever fields we extracted
    }

    if (fields.length !== headers.length) {
      errors.push({
        row: rowNum,
        message: `Column count mismatch: expected ${headers.length}, got ${fields.length}`,
      });
    }

    const record: Record<string, unknown> = {};
    for (let c = 0; c < headers.length; c++) {
      const raw = c < fields.length ? fields[c] : "";
      record[headers[c]] = shouldCoerce ? coerce(raw) : raw;
    }
    rows.push(record);
  }

  return buildResult(headers, rows, errors);
}

// ─── Result builder ─────────────────────────────────────────────────────────

function buildResult(
  headers: string[],
  rows: Record<string, unknown>[],
  errors: CSVError[]
): CSVResult {
  return {
    headers,
    rows,
    errors,

    filter(predicate: (row: Record<string, unknown>) => boolean): Record<string, unknown>[] {
      return rows.filter(predicate);
    },

    sum(column: string): number {
      let total = 0;
      for (const row of rows) {
        const val = row[column];
        if (typeof val === "number") {
          total += val;
        }
      }
      return total;
    },

    average(column: string): number {
      let total = 0;
      let count = 0;
      for (const row of rows) {
        const val = row[column];
        if (typeof val === "number") {
          total += val;
          count++;
        }
      }
      return count === 0 ? 0 : total / count;
    },

    count(): number {
      return rows.length;
    },

    groupBy(column: string): Map<unknown, Record<string, unknown>[]> {
      const map = new Map<unknown, Record<string, unknown>[]>();
      for (const row of rows) {
        const key = row[column];
        let group = map.get(key);
        if (!group) {
          group = [];
          map.set(key, group);
        }
        group.push(row);
      }
      return map;
    },
  };
}

import { parseCSV, CSVResult } from "./csv-parser";

// ─── Tiny assertion helpers ─────────────────────────────────────────────────

let passed = 0;
let failed = 0;
const failures: string[] = [];

function assert(condition: boolean, message: string): void {
  if (!condition) {
    failed++;
    failures.push(message);
    console.error(`  ✗ ${message}`);
  } else {
    passed++;
    console.log(`  ✓ ${message}`);
  }
}

function assertEqual(actual: unknown, expected: unknown, label: string): void {
  const a = JSON.stringify(actual);
  const e = JSON.stringify(expected);
  assert(a === e, `${label}  (expected ${e}, got ${a})`);
}

function assertClose(actual: number, expected: number, tolerance: number, label: string): void {
  assert(
    Math.abs(actual - expected) <= tolerance,
    `${label}  (expected ≈${expected}, got ${actual})`
  );
}

function section(name: string): void {
  console.log(`\n── ${name} ${"─".repeat(60 - name.length)}`);
}

// ═══════════════════════════════════════════════════════════════════════════════
// Tests
// ═══════════════════════════════════════════════════════════════════════════════

// ── 1. Basic parsing ────────────────────────────────────────────────────────

section("Basic parsing");

{
  const csv = "name,age,city\nAlice,30,New York\nBob,25,London";
  const result = parseCSV(csv);

  assertEqual(result.headers, ["name", "age", "city"], "Headers parsed correctly");
  assertEqual(result.rows.length, 2, "Correct number of rows");
  assertEqual(result.rows[0]["name"], "Alice", "First row name");
  assertEqual(result.rows[0]["age"], 30, "First row age (number)");
  assertEqual(result.rows[0]["city"], "New York", "First row city");
  assertEqual(result.rows[1]["name"], "Bob", "Second row name");
  assertEqual(result.rows[1]["age"], 25, "Second row age");
  assertEqual(result.rows[1]["city"], "London", "Second row city");
  assertEqual(result.errors.length, 0, "No errors");
}

// ── 2. Quoted fields with commas ────────────────────────────────────────────

section("Quoted fields with commas");

{
  const csv = 'name,address,city\nAlice,"123 Main St, Apt 4",Springfield\nBob,"456 Oak Ave, Suite 100",Shelbyville';
  const result = parseCSV(csv);

  assertEqual(result.rows[0]["address"], "123 Main St, Apt 4", "Comma inside quoted field");
  assertEqual(result.rows[1]["address"], "456 Oak Ave, Suite 100", "Second quoted field with comma");
  assertEqual(result.errors.length, 0, "No errors for quoted fields");
}

// ── 3. Escaped quotes ──────────────────────────────────────────────────────

section("Escaped quotes");

{
  const csv = 'name,quote\nAlice,"She said ""hello"""\nBob,"He replied ""goodbye""!"';
  const result = parseCSV(csv);

  assertEqual(result.rows[0]["quote"], 'She said "hello"', "Escaped double quotes (first row)");
  assertEqual(result.rows[1]["quote"], 'He replied "goodbye"!', "Escaped double quotes (second row)");
  assertEqual(result.errors.length, 0, "No errors for escaped quotes");
}

{
  const csv = 'val\n""""""\n""""""';
  const result = parseCSV(csv);
  assertEqual(result.rows[0]["val"], '""', "Triple escaped quotes produce two literal quotes");
}

// ── 4. Custom delimiters ────────────────────────────────────────────────────

section("Custom delimiters");

{
  const csv = "name\tage\tcity\nAlice\t30\tNew York\nBob\t25\tLondon";
  const result = parseCSV(csv, { delimiter: "\t" });

  assertEqual(result.headers, ["name", "age", "city"], "Tab-delimited headers");
  assertEqual(result.rows[0]["name"], "Alice", "Tab-delimited first row");
  assertEqual(result.rows[0]["age"], 30, "Tab-delimited age coerced");
}

{
  const csv = "name;age;city\nAlice;30;Paris";
  const result = parseCSV(csv, { delimiter: ";" });

  assertEqual(result.headers, ["name", "age", "city"], "Semicolon-delimited headers");
  assertEqual(result.rows[0]["city"], "Paris", "Semicolon-delimited value");
}

{
  const csv = "name|age\nAlice|30";
  const result = parseCSV(csv, { delimiter: "|" });

  assertEqual(result.rows[0]["name"], "Alice", "Pipe-delimited");
}

// Custom quote character
{
  const csv = "name,address\nAlice,'123 Main, Apt 4'";
  const result = parseCSV(csv, { quote: "'" });

  assertEqual(result.rows[0]["address"], "123 Main, Apt 4", "Single-quote as quote char");
}

// Custom line separator
{
  const csv = "name,age|Alice,30|Bob,25";
  const result = parseCSV(csv, { lineSeparator: "|" });

  assertEqual(result.rows.length, 2, "Pipe line separator yields 2 rows");
  assertEqual(result.rows[0]["name"], "Alice", "Custom line sep first row");
}

// ── 5. Type coercion ────────────────────────────────────────────────────────

section("Type coercion – numbers");

{
  const csv = "val\n42\n-7\n3.14\n0\n+5\n.5\n1e3\n1.5e2";
  const result = parseCSV(csv);

  assertEqual(result.rows[0]["val"], 42, "Integer");
  assertEqual(result.rows[1]["val"], -7, "Negative integer");
  assertEqual(result.rows[2]["val"], 3.14, "Float");
  assertEqual(result.rows[3]["val"], 0, "Zero");
  assertEqual(result.rows[4]["val"], 5, "Positive with +");
  assertEqual(result.rows[5]["val"], 0.5, "Leading dot float");
  assertEqual(result.rows[6]["val"], 1000, "Scientific notation 1e3");
  assertEqual(result.rows[7]["val"], 150, "Scientific notation 1.5e2");
}

section("Type coercion – booleans");

{
  const csv = "val\ntrue\nfalse\nTRUE\nFALSE\nTrue\nFalse";
  const result = parseCSV(csv);

  assertEqual(result.rows[0]["val"], true, "true");
  assertEqual(result.rows[1]["val"], false, "false");
  assertEqual(result.rows[2]["val"], true, "TRUE");
  assertEqual(result.rows[3]["val"], false, "FALSE");
  assertEqual(result.rows[4]["val"], true, "True");
  assertEqual(result.rows[5]["val"], false, "False");
}

section("Type coercion – nulls");

{
  const csv = "a,b,c\nnull,NULL,";
  const result = parseCSV(csv);

  assertEqual(result.rows[0]["a"], null, '"null" → null');
  assertEqual(result.rows[0]["b"], null, '"NULL" → null');
  assertEqual(result.rows[0]["c"], null, 'empty string → null');
}

section("Type coercion – strings preserved");

{
  const csv = "val\nhello world\n123abc\ntrue_ish\nnullx";
  const result = parseCSV(csv);

  assertEqual(result.rows[0]["val"], "hello world", "Plain string");
  assertEqual(result.rows[1]["val"], "123abc", "Alphanumeric stays string");
  assertEqual(result.rows[2]["val"], "true_ish", "Almost-boolean stays string");
  assertEqual(result.rows[3]["val"], "nullx", "Almost-null stays string");
}

section("Type coercion disabled");

{
  const csv = "val\n42\ntrue\nnull";
  const result = parseCSV(csv, { typeCoercion: false });

  assertEqual(result.rows[0]["val"], "42", "Number stays string when coercion off");
  assertEqual(result.rows[1]["val"], "true", "Boolean stays string when coercion off");
  assertEqual(result.rows[2]["val"], "null", "Null stays string when coercion off");
}

// ── 6. Malformed rows / error collection ────────────────────────────────────

section("Error collection – column count mismatch");

{
  const csv = "a,b,c\n1,2,3\n4,5\n6,7,8,9";
  const result = parseCSV(csv);

  assertEqual(result.rows.length, 3, "All rows still parsed");
  assert(result.errors.length >= 2, `At least 2 errors collected (got ${result.errors.length})`);

  // Row 3 (1-based) has too few columns
  const tooFew = result.errors.find((e) => e.row === 3);
  assert(tooFew !== undefined, "Error for row with too few columns");
  assert(tooFew!.message.includes("mismatch"), "Error message mentions mismatch");

  // Row 4 has too many columns
  const tooMany = result.errors.find((e) => e.row === 4);
  assert(tooMany !== undefined, "Error for row with too many columns");
}

section("Error collection – unterminated quote");

{
  const csv = 'a,b\n"unterminated,value\nnext,row';
  const result = parseCSV(csv);

  assert(result.errors.length > 0, "Error collected for unterminated quote");
  const err = result.errors.find((e) => e.message.includes("Unterminated"));
  assert(err !== undefined, "Unterminated quote error found");
}

section("Error collection – does not crash");

{
  // Various weird inputs should never throw
  const weirdInputs = [
    '"""',
    '"\n"',
    "a\n,,,,,",
    'a\n"x""',
    ",\n,",
  ];
  for (const input of weirdInputs) {
    let didThrow = false;
    try {
      parseCSV(input);
    } catch {
      didThrow = true;
    }
    assert(!didThrow, `No crash on weird input: ${JSON.stringify(input)}`);
  }
}

// ── 7. Filter ───────────────────────────────────────────────────────────────

section("Filter");

{
  const csv = "name,age,active\nAlice,30,true\nBob,25,false\nCharlie,35,true";
  const result = parseCSV(csv);

  const adults = result.filter((r) => (r["age"] as number) >= 30);
  assertEqual(adults.length, 2, "Filter by age >= 30 returns 2 rows");
  assertEqual(adults[0]["name"], "Alice", "First filtered row");
  assertEqual(adults[1]["name"], "Charlie", "Second filtered row");

  const active = result.filter((r) => r["active"] === true);
  assertEqual(active.length, 2, "Filter by active === true");

  const none = result.filter(() => false);
  assertEqual(none.length, 0, "Filter returning none");

  const all = result.filter(() => true);
  assertEqual(all.length, 3, "Filter returning all");
}

// ── 8. Aggregation ──────────────────────────────────────────────────────────

section("Aggregation – sum");

{
  const csv = "item,price,qty\nApple,1.5,10\nBanana,0.75,20\nCherry,2.0,5";
  const result = parseCSV(csv);

  assertClose(result.sum("price"), 4.25, 0.001, "Sum of prices");
  assertEqual(result.sum("qty"), 35, "Sum of quantities");
  assertEqual(result.sum("item"), 0, "Sum of non-numeric column = 0");
  assertEqual(result.sum("nonexistent"), 0, "Sum of missing column = 0");
}

section("Aggregation – average");

{
  const csv = "name,score\nAlice,90\nBob,80\nCharlie,70";
  const result = parseCSV(csv);

  assertClose(result.average("score"), 80, 0.001, "Average of scores");
  assertEqual(result.average("name"), 0, "Average of non-numeric column = 0");
  assertEqual(result.average("nonexistent"), 0, "Average of missing column = 0");
}

{
  const csv = "val\n10\nnull\n20\n";
  const result = parseCSV(csv);
  // null values should not count — only 10 and 20 → avg = 15
  assertClose(result.average("val"), 15, 0.001, "Average ignores null values");
}

section("Aggregation – count");

{
  const csv = "a\n1\n2\n3\n4\n5";
  const result = parseCSV(csv);
  assertEqual(result.count(), 5, "Count returns total rows");
}

{
  const result = parseCSV("");
  assertEqual(result.count(), 0, "Count on empty input = 0");
}

section("Aggregation – groupBy");

{
  const csv = "dept,name,salary\nEng,Alice,100\nEng,Bob,110\nHR,Charlie,90\nHR,Diana,95\nEng,Eve,120";
  const result = parseCSV(csv);
  const groups = result.groupBy("dept");

  assertEqual(groups.size, 2, "Two groups");
  assertEqual(groups.get("Eng")!.length, 3, "Eng group has 3 members");
  assertEqual(groups.get("HR")!.length, 2, "HR group has 2 members");
  assertEqual(groups.get("Eng")![0]["name"], "Alice", "First Eng member");
}

{
  const csv = "val,label\nnull,a\nnull,b\n1,c";
  const result = parseCSV(csv);
  const groups = result.groupBy("val");

  assert(groups.has(null), "Can group by null values");
  assertEqual(groups.get(null)!.length, 2, "Two rows with null key");
}

// ── 9. Edge cases ───────────────────────────────────────────────────────────

section("Edge case – empty input");

{
  const result = parseCSV("");
  assertEqual(result.headers.length, 0, "No headers");
  assertEqual(result.rows.length, 0, "No rows");
  assertEqual(result.errors.length, 0, "No errors");
}

{
  const result = parseCSV("   \n  \n ");
  assertEqual(result.rows.length, 0, "Whitespace-only input → no rows");
}

section("Edge case – headers only, no data");

{
  const csv = "name,age,city";
  const result = parseCSV(csv);
  assertEqual(result.headers, ["name", "age", "city"], "Headers parsed");
  assertEqual(result.rows.length, 0, "No data rows");
}

section("Edge case – single column");

{
  const csv = "value\n1\n2\n3";
  const result = parseCSV(csv);

  assertEqual(result.headers, ["value"], "Single header");
  assertEqual(result.rows.length, 3, "Three rows");
  assertEqual(result.rows[0]["value"], 1, "First value");
}

section("Edge case – single row");

{
